const mongoose = require('mongoose');

const userSchema = new mongoose.Schema({
    firebaseUid: {
        type: String,
        required: true,
        unique: true
    },
    email: {
        type: String,
        required: true,
        unique: true
    },
    name: {
        type: String,
        default: "Unknown"
    },
    role: {
        type: String,
        enum: ['user', 'admin', 'police'],
        default: 'user'
    },
    createdAt: {
        type: Date,
        default: Date.now
    }
});

