    // --- NEW FEATURE: Incident Timeline Data ---
    const timelineEvents = [
        { id: 1, type: "Panic SOS Triggered", time: "10:30 PM", loc: "Mall Road, Darjeeling" },
        { id: 2, type: "Route Deviated", time: "9:15 PM", loc: "Chowrasta" },
